"use client"

import { useEffect, useRef } from 'react'
import { X } from 'lucide-react'
import { Button } from './ui/button'

interface ContactModalProps {
    open: boolean
    onClose: () => void
}

export default function ContactModal({ open, onClose }: ContactModalProps) {
    const modalRef = useRef<HTMLDivElement>(null)

    useEffect(() => {
        if (!open) return
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose()
        }
        document.addEventListener('keydown', handleKeyDown)
        document.body.style.overflow = 'hidden'
        return () => {
            document.removeEventListener('keydown', handleKeyDown)
            document.body.style.overflow = ''
        }
    }, [open, onClose])

    if (!open) return null

    return (
        <div
            className="fixed inset-0 z-[100] flex items-center justify-center p-4"
            onClick={(e) => {
                if (e.target === e.currentTarget) onClose()
            }}
        >
            {/* Backdrop */}
            <div className="absolute inset-0 bg-black/50 backdrop-blur-sm animate-fadeIn" />

            {/* Modal */}
            <div
                ref={modalRef}
                className="relative w-full max-w-[480px] bg-white dark:bg-gray-900 rounded-2xl shadow-2xl p-8 animate-modalIn"
            >
                {/* Close button */}
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 p-1.5 rounded-full text-gray-400 hover:text-gray-900 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                >
                    <X className="w-5 h-5" />
                </button>

                <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-1">
                    Start a project
                </h2>
                <p className="text-gray-500 dark:text-gray-400 text-sm mb-6">
                    Tell me about your project and I'll get back to you shortly.
                </p>

                <form className="space-y-4" onSubmit={(e) => e.preventDefault()}>
                    {/* Name */}
                    <div>
                        <label htmlFor="name" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                            Name
                        </label>
                        <input
                            id="name"
                            type="text"
                            placeholder="Your name"
                            className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-gray-900 dark:text-white text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-gray-900 dark:focus:ring-white/20 transition-shadow"
                        />
                    </div>

                    {/* Email */}
                    <div>
                        <label htmlFor="email" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                            Email
                        </label>
                        <input
                            id="email"
                            type="email"
                            placeholder="you@example.com"
                            className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-gray-900 dark:text-white text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-gray-900 dark:focus:ring-white/20 transition-shadow"
                        />
                    </div>

                    {/* Budget & Service row */}
                    <div className="grid grid-cols-2 gap-3">
                        {/* Budget */}
                        <div>
                            <label htmlFor="budget" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                                Budget
                            </label>
                            <select
                                id="budget"
                                defaultValue=""
                                className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-gray-900 dark:text-white text-sm focus:outline-none focus:ring-2 focus:ring-gray-900 dark:focus:ring-white/20 transition-shadow appearance-none"
                            >
                                <option value="" disabled>Select range</option>
                                <option value="1k-5k">$1k – $5k</option>
                                <option value="5k-10k">$5k – $10k</option>
                                <option value="10k-25k">$10k – $25k</option>
                                <option value="25k+">$25k+</option>
                            </select>
                        </div>

                        {/* Service */}
                        <div>
                            <label htmlFor="service" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                                Service
                            </label>
                            <select
                                id="service"
                                defaultValue=""
                                className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-gray-900 dark:text-white text-sm focus:outline-none focus:ring-2 focus:ring-gray-900 dark:focus:ring-white/20 transition-shadow appearance-none"
                            >
                                <option value="" disabled>Select service</option>
                                <option value="web-design">Web Design</option>
                                <option value="frontend-dev">Frontend Development</option>
                                <option value="product-design">Full Product Design</option>
                                <option value="other">Other</option>
                            </select>
                        </div>
                    </div>

                    {/* Description */}
                    <div>
                        <label htmlFor="description" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                            Description
                        </label>
                        <textarea
                            id="description"
                            rows={4}
                            placeholder="Tell me about your project..."
                            className="w-full px-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-gray-900 dark:text-white text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-gray-900 dark:focus:ring-white/20 transition-shadow resize-none"
                        />
                    </div>

                    {/* Submit */}
                    <Button
                        type="submit"
                        size="lg"
                        className="w-full rounded-full bg-[#1A1A1A] dark:bg-white text-white dark:text-gray-900 hover:bg-gray-800 dark:hover:bg-gray-100 py-3 text-sm font-medium transition-colors"
                    >
                        Send message
                    </Button>
                </form>
            </div>
        </div>
    )
}
